values ((select id from public.consulta_vet_categories where slug = 'infecciosas'), 'cinomose-canina', 'Cinomose Canina', array['Distemper canino']::text[], array['dog']::text[], array['Viral', 'Neurológica', 'Vacinação', 'Filhotes']::text[], 'Doença viral sistêmica com acometimento respiratório, gastrointestinal e neurológico. A prova de conceito do módulo prioriza reconhecimento clínico, suporte intensivo e controle de complicações secundárias.', array['Pense em cinomose em cão jovem, não vacinado, com sinais multissistêmicos.', 'Mioclonia, hiperqueratose de coxins e progressão neurológica têm alto peso clínico.', 'Não existe antiviral curativo de rotina: o diferencial é suporte, isolamento e monitorização precoce.']::text[], array['Sinais neurológicos podem surgir dias ou semanas após a fase respiratória ou digestiva.', 'Resultados negativos em teste rápido não excluem a doença em paciente muito sugestivo.', 'Isolamento é parte do tratamento e protege outros pacientes internados.']::text[], array['Filhote ou adulto jovem sem protocolo vacinal completo.', 'Secreção ocular ou nasal, tosse e apatia associados a vômito ou diarreia.', 'Mioclonia, convulsões, ataxia ou déficits proprioceptivos em conjunto com histórico compatível.']::text[], array['Isolar o paciente e estabilizar hidratação, perfusão e controle de vômito.', 'Coletar PCR ou teste específico antes de antibiótico quando possível, sem atrasar suporte.', 'Tratar complicações bacterianas e neurológicas de acordo com apresentação clínica.']::text[], array['RT-PCR em swab conjuntival, secreção nasal, urina ou sangue.', 'Hemograma para leucopenia, linfopenia e avaliação de infecção secundária.', 'Radiografia torácica quando houver tosse, crepitações ou suspeita de broncopneumonia.']::text[], array[]::text[], array['Esperar confirmação laboratorial para iniciar suporte em paciente claramente instável.', 'Subestimar mioclonia e sinais discretos de déficit neurológico.', 'Usar antibiótico de forma indiscriminada sem justificar infecção bacteriana secundária.']::text[], array['Convulsões, mioclonia persistente ou alteração aguda do estado mental.', 'Hipoxemia, esforço respiratório ou broncopneumonia com suspeita de sepse secundária.', 'Desidratação importante com recusa alimentar e evolução rápida.', 'Filhote não vacinado com leucopenia acentuada e piora progressiva.']::text[], array['Mioclonia em cão jovem não vacinado tem alto valor sugestivo no contexto correto.', 'A cinomose pode simular doença respiratória ou gastroenterite nos primeiros dias.', 'O prognóstico piora muito quando o acometimento neurológico já é estabelecido.']::text[], '"A cinomose canina é uma enfermidade infecciosa altamente contagiosa, de grande impacto em filhotes e em pacientes com baixa cobertura vacinal. O vírus pode produzir quadro multissistêmico, com intensidade variável entre formas leves e encefalomielite progressiva."'::jsonb, '"Causada pelo canine distemper virus (CDV), um Morbillivirus envelopado, sensível a desinfetantes usuais, mas altamente transmissível em populações suscetíveis."'::jsonb, '["Contato direto com secreções respiratórias, oculares, saliva, urina ou fezes de animais infectados.","Aerossois em locais com alta densidade de cães, como abrigos, creches e internações.","Eliminação viral pode persistir por semanas mesmo após melhora clínica parcial."]'::jsonb, '{"Resposta imune e progressão":["Após replicar em tonsilas e linfonodos regionais, o vírus induz imunossupressão transitória com linfopenia.","Se a resposta imune é insuficiente, ocorre disseminação para epitélios, pele e sistema nervoso central.","O acometimento neurológico envolve inflamação, desmielinização e lesão viral direta."],"Sistemas acometidos":["Respiratório: rinite, secreção ocular ou nasal, tosse e broncopneumonia.","Gastrointestinal: vômito, diarreia, anorexia e perda de peso.","Cutâneo: hiperqueratose de coxins e plano nasal em fases tardias.","Neurológico: ataxia, paresia, mioclonia, convulsões e alterações comportamentais."]}'::jsonb, '"Mais frequente em cães jovens entre 3 e 6 meses, especialmente sem vacinação primária completa. Surtos ainda ocorrem em cenários de baixa adesão vacinal e alta rotatividade de animais."'::jsonb, '{"Fase inicial":["Febre, apatia e queda do apetite.","Secreção ocular e nasal serosa evoluindo para mucopurulenta.","Tosse, espirros e sinais de bronquite ou pneumonia."],"Fase digestiva":["Vômito e diarreia com risco de desidratação e desequilíbrio eletrolítico.","Perda ponderal rápida em pacientes com anorexia persistente."],"Fase neurológica":["Mioclonia focal ou generalizada.","Ataxia, tetraparesia, déficits proprioceptivos e hiperestesia.","Convulsões e alteração do estado mental."]}'::jsonb, '["Avaliar hidratação, temperatura, padrão respiratório e secreções oculares ou nasais.","Inspecionar coxins plantares e plano nasal em busca de hiperqueratose.","Realizar exame neurológico completo sempre que houver mioclonia, tremores ou ataxia.","Auscultar tórax e palpar linfonodos periféricos."]'::jsonb, '["Traqueobronquite infecciosa canina e outras doenças respiratórias infecciosas.","Parvovirose ou outras gastroenterites infecciosas em filhotes.","Meningoencefalites infecciosas ou inflamatórias.","Toxoplasmose, neosporose e intoxicações em pacientes neurológicos."]'::jsonb, '{"Exames laboratoriais":["Hemograma pode revelar leucopenia, linfopenia e leucocitose tardia por infecção bacteriana secundária.","Bioquímica ajuda a avaliar hidratação, eletrólitos e funções hepática e renal."],"Testes específicos":["RT-PCR em swab conjuntival, secreção nasal, sangue ou urina tem bom rendimento nas fases iniciais.","Imunocromatografia rápida pode ajudar na triagem, mas não exclui a doença quando negativa.","Citologia de conjuntiva ou sedimento urinário pode mostrar corpúsculos de inclusão, com sensibilidade limitada."],"Imagem e suporte":["Radiografia torácica é útil quando há suspeita de broncopneumonia.","Líquor e imagem avançada entram em casos neurológicos selecionados."]}'::jsonb, '"Priorizar histórico vacinal, idade, ambiente, evolução clínica e sinais multissistêmicos. Em paciente suspeito, coletar exame específico precocemente, corrigir desidratação e tratar complicações concomitantes."'::jsonb, '{"Conduta de suporte":["Fluidoterapia e correção de distúrbios hidroeletrolíticos.","Controle de vômito, suporte nutricional e manejo intensivo de pacientes anorexicos.","Nebulização, fisioterapia respiratória e oxigenioterapia quando indicadas."],"Controle de complicações":["Antimicrobiano apenas quando houver evidência ou forte suspeita de infecção bacteriana secundária.","Anticonvulsivantes conforme o padrão de acometimento neurológico.","Cuidados de enfermagem e prevenção de lesões por decúbito."],"Monitorizacao":["Reavaliar hidratação, estado mental, frequência de crises e progressão respiratória.","Alinhar com tutor que o tratamento é de suporte e o prognóstico depende principalmente do SNC."]}'::jsonb, '"Variável. Casos com apresentação respiratória ou digestiva leve podem evoluir bem com suporte adequado. Já pacientes com acometimento neurológico progressivo têm prognóstico reservado a desfavorável."'::jsonb, '["Broncopneumonia bacteriana secundária.","Encefalomielite e sequelas neurológicas permanentes.","Desnutrição, lesões de decúbito e infecções oportunistas em internação prolongada."]'::jsonb, '["Vacinação essencial com protocolo primário completo e reforços conforme risco individual.","Isolamento rigoroso de pacientes suspeitos ou confirmados.","Higienização ambiental e controle de circulação em abrigos e clínicas.","Orientação intensiva a tutores de filhotes e pacientes de risco."]'::jsonb, '[{"citationText":"MSD Veterinary Manual. Canine Distemper.","sourceType":"Manual","url":"https://www.msdvetmanual.com","notes":"Visão geral clínica, transmissão e diagnóstico de cinomose canina."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, synonyms = excluded.synonyms, species = excluded.species, tags = excluded.tags, quick_summary = excluded.quick_summary, thirty_second_view = excluded.thirty_second_view, do_not_forget = excluded.do_not_forget, when_to_suspect = excluded.when_to_suspect, initial_conduct = excluded.initial_conduct, high_yield_tests = excluded.high_yield_tests, dog_vs_cat_differences = excluded.dog_vs_cat_differences, common_mistakes = excluded.common_mistakes, red_flags = excluded.red_flags, clinical_pearls = excluded.clinical_pearls, introduction = excluded.introduction, etiology = excluded.etiology, transmission = excluded.transmission, pathophysiology = excluded.pathophysiology, epidemiology = excluded.epidemiology, clinical_presentation = excluded.clinical_presentation, physical_exam = excluded.physical_exam, differential_diagnoses = excluded.differential_diagnoses, diagnostics = excluded.diagnostics, diagnostic_approach = excluded.diagnostic_approach, treatment = excluded.treatment, prognosis = excluded.prognosis, complications = excluded.complications, prevention = excluded.prevention, "references" = excluded."references", is_published = excluded.is_published;

