values ((select id from public.consulta_vet_categories where slug = 'infecciosas'), 'leishmaniose-visceral-canina', 'Leishmaniose Visceral Canina', array['LVC', 'Calazar canino']::text[], array['dog']::text[], array['Zoonose', 'Vetor', 'Crônica']::text[], 'Doença infecciosa sistêmica causada por Leishmania infantum, com evolução crônica, impacto cutâneo, renal e hematolinfático e forte relevância em saúde pública.', array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array['Azotemia em progressão ou proteinúria importante.', 'Epistaxe intensa, uveíte grave ou sangramentos espontâneos.', 'Perda de peso marcada com comprometimento sistêmico avançado.']::text[], array['Nem todo cão infectado é clinicamente doente; o estadiamento muda a conduta.', 'UPC e perfil renal são decisivos antes e durante o tratamento.', 'Controle vetorial continua obrigatório mesmo com melhora clínica.']::text[], '"A leishmaniose visceral canina combina manifestações dermatológicas, renais, oculares e hematológicas em intensidade variável. O cão é um reservatório urbano relevante, e o manejo exige visão clínica e epidemiológica."'::jsonb, '"Causada por Leishmania infantum, protozoário intracelular obrigatório com replicação em macrófagos."'::jsonb, '["Picada de flebotomíneos infectados em áreas endêmicas.","Transmissão vertical e venérea são descritas, porém menos frequentes."]'::jsonb, '"Resposta imune ineficaz favorece alta carga parasitária, formação de imunocomplexos e lesão orgânica progressiva, sobretudo glomerulonefrite, vasculite e inflamação cutânea crônica."'::jsonb, '"Endêmica em diversas regiões do Brasil, com maior impacto em áreas de circulação vetorial e baixa proteção ambiental."'::jsonb, '["Linfadenomegalia, emagrecimento e hiporexia.","Dermatopatias crônicas, alopecia periocular, descamação e úlceras.","Onicogrifose, epistaxe, uveíte e sinais compatíveis com doença renal."]'::jsonb, '["Palpar linfonodos, baço e avaliar condição corporal.","Inspecionar pele, unhas, mucosas e olhos.","Pesquisar desidratação, perfusão e sinais de sangramento."]'::jsonb, '["Ehrlichiose e outras hemoparasitoses.","Doenças autoimunes.","Dermatopatias infecciosas ou parasitárias crônicas."]'::jsonb, '{"Sorologia":["DPP como teste inicial conforme protocolo de triagem.","ELISA como confirmação, interpretado com contexto clínico."],"Parasitologia e molecular":["Citologia de linfonodo, medula ou lesão cutânea pode mostrar amastigotas.","PCR auxilia em casos duvidosos e em amostras específicas."],"Avaliação complementar":["Hemograma, bioquímica, urinálise e UPC são obrigatórios para estadiamento."]}'::jsonb, '"Confirmar a suspeita com testes específicos e sempre estadiar o paciente antes da terapia. Avaliação renal e proteinúria são mandatórias."'::jsonb, '{"Base terapêutica":["Miltefosina e alopurinol são combinações frequentes no manejo clínico.","Tratar complicações renais, oculares e cutâneas em paralelo."],"Seguimento":["Monitorar UPC, creatinina, hemograma e resposta clínica em intervalos regulares.","Reforçar repelência e medidas ambientais para reduzir transmissão."]}'::jsonb, '"Depende principalmente do estágio clínico e do comprometimento renal. Casos precoces podem permanecer compensados por longos períodos; pacientes com doença renal avançada têm prognóstico reservado."'::jsonb, '["Doença renal crônica progressiva.","Hiperviscosidade por hiperglobulinemia importante.","Recidiva clínica após melhora inicial."]'::jsonb, '["Repelentes tópicos e coleiras com eficácia vetorial.","Vacinação conforme indicação e protocolo vigente.","Manejo ambiental e proteção nos horários de maior atividade do vetor."]'::jsonb, '[{"citationText":"Brasileish. Diretrizes Brasileiras para o Manejo da Leishmaniose Visceral Canina (2020).","sourceType":"Consenso","url":"https://www.brasileish.com.br/wp-content/uploads/2020/12/Diretrizes-Brasileish-2020.pdf","notes":"Base para diagnóstico, estadiamento e tratamento da LVC no Brasil."},{"citationText":"LeishVet Group. Practical management of canine leishmaniosis.","sourceType":"Guideline","url":"https://www.leishvet.org","notes":"Diretrizes internacionais para manejo clínico e seguimento."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, synonyms = excluded.synonyms, species = excluded.species, tags = excluded.tags, quick_summary = excluded.quick_summary, thirty_second_view = excluded.thirty_second_view, do_not_forget = excluded.do_not_forget, when_to_suspect = excluded.when_to_suspect, initial_conduct = excluded.initial_conduct, high_yield_tests = excluded.high_yield_tests, dog_vs_cat_differences = excluded.dog_vs_cat_differences, common_mistakes = excluded.common_mistakes, red_flags = excluded.red_flags, clinical_pearls = excluded.clinical_pearls, introduction = excluded.introduction, etiology = excluded.etiology, transmission = excluded.transmission, pathophysiology = excluded.pathophysiology, epidemiology = excluded.epidemiology, clinical_presentation = excluded.clinical_presentation, physical_exam = excluded.physical_exam, differential_diagnoses = excluded.differential_diagnoses, diagnostics = excluded.diagnostics, diagnostic_approach = excluded.diagnostic_approach, treatment = excluded.treatment, prognosis = excluded.prognosis, complications = excluded.complications, prevention = excluded.prevention, "references" = excluded."references", is_published = excluded.is_published;

