values ((select id from public.consulta_vet_categories where slug = 'nefrologia'), 'doenca-renal-cronica', 'Doença Renal Crônica', array['DRC', 'IRC']::text[], array['dog', 'cat']::text[], array['IRIS', 'Proteinúria', 'Hipertensão']::text[], 'Perda progressiva e irreversível da função renal, com impacto em hidratação, excreção de toxinas, pressão arterial e qualidade de vida de cães e gatos.', array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array[]::text[], array['Crise urêmica com vômito incoercível, letargia intensa e úlceras orais.', 'Hipertensão grave com risco ocular ou neurológico.', 'Oligúria, anúria ou piora abrupta sobre quadro crônico.']::text[], array['SDMA pode identificar redução de filtração antes da creatinina em alguns pacientes.', 'Dieta renal é uma das intervenções com maior impacto na progressão.', 'Proteinúria e pressão arterial devem ser avaliadas em todo paciente com DRC.']::text[], '"A doença renal crônica é frequente em pacientes geriátricos e exige abordagem longitudinal. O diagnóstico não se resume à creatinina elevada: envolve densidade urinária, biomarcadores, proteinúria, imagem e pressão arterial."'::jsonb, '"Frequentemente idiopática, mas também associada a lesões renais agudas prévias, nefrites crônicas, glomerulopatias, anomalias congênitas e nefrolitíase."'::jsonb, '"Não se aplica. Trata-se de doença não infecciosa."'::jsonb, '"A perda de néfrons gera hiperfiltração compensatória nos remanescentes, porém à custa de maior lesão glomerular e progressão estrutural. O resultado é retenção de toxinas urêmicas, distúrbios do fósforo, anemia e alterações pressóricas."'::jsonb, '"Mais comum em animais idosos, especialmente gatos. A prevalência aumenta com a idade e com a presença de comorbidades sistêmicas."'::jsonb, '["Poliúria e polidipsia persistentes.","Perda de peso, hiporexia, letargia e pelagem opaca.","Náusea, vômito, halitose urêmica e desidratação recorrente.","Em alguns pacientes, cegueira súbita por hipertensão sistêmica."]'::jsonb, '["Avaliar hidratação, condição corporal e massa muscular.","Mensurar pressão arterial sistólica.","Palpar rins e pesquisar dor, assimetria ou tamanho reduzido.","Inspecionar fundo de olho quando houver suspeita de hipertensão."]'::jsonb, '["Lesão renal aguda.","Diabetes mellitus e outras causas de poliúria e polidipsia.","Hipertireoidismo em gatos.","Doenças hepáticas e endocrinopatias com repercussão sistêmica."]'::jsonb, '{"Laboratorio":["Creatinina, ureia, SDMA, fósforo e potássio conforme estágio.","Hemograma para anemia arregenerativa e avaliação inflamatória."],"Urinalise":["Densidade urinária inadequadamente concentrada.","UPC para subestadiamento e tomada de decisão terapêutica."],"Imagem e monitorizacao":["Ultrassonografia renal para arquitetura, tamanho e exclusão de obstrução.","Pressão arterial sistólica como parte obrigatória do estadiamento."]}'::jsonb, '"Confirmar persistência do quadro, excluir injúria aguda isolada e classificar conforme diretrizes IRIS. O estadiamento orienta dieta, controle pressórico, manejo de fósforo e acompanhamento."'::jsonb, '{"Medidas centrais":["Dieta renal, controle de fósforo e correção de desidratação.","Controle de proteinúria e hipertensão com terapia específica.","Manejo de náusea, vômito, anorexia e constipação quando presentes."],"Seguimento":["Reavaliações seriadas com creatinina, SDMA, fósforo, UPC e pressão arterial.","Ajuste terapêutico conforme progressão clínica e laboratorial."]}'::jsonb, '"Variável e diretamente relacionado ao estágio IRIS, à presença de proteinúria, hipertensão e à adesão ao tratamento. Casos leves podem permanecer estáveis por longos períodos."'::jsonb, '["Hipertensão arterial sistêmica.","Crise urêmica.","Anemia de doença renal crônica.","Progressão para estágios terminais com perda importante de qualidade de vida."]'::jsonb, '["Check-ups regulares em pacientes maduros e geriátricos.","Acesso amplo à água e monitoramento precoce de alterações urinárias.","Uso criterioso de fármacos potencialmente nefrotóxicos."]'::jsonb, '[{"citationText":"International Renal Interest Society (IRIS). IRIS Staging of CKD modified 2023.","sourceType":"Guideline","url":"http://www.iris-kidney.com/pdf/IRIS_Staging_of_CKD_modified_2023.pdf","notes":"Estadiamento de DRC em cães e gatos com subestadiamento por proteinúria e pressão arterial."},{"citationText":"International Renal Interest Society (IRIS). Treatment Recommendations for CKD.","sourceType":"Guideline","url":"http://www.iris-kidney.com","notes":"Recomendações terapêuticas e de monitorização longitudinal."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, synonyms = excluded.synonyms, species = excluded.species, tags = excluded.tags, quick_summary = excluded.quick_summary, thirty_second_view = excluded.thirty_second_view, do_not_forget = excluded.do_not_forget, when_to_suspect = excluded.when_to_suspect, initial_conduct = excluded.initial_conduct, high_yield_tests = excluded.high_yield_tests, dog_vs_cat_differences = excluded.dog_vs_cat_differences, common_mistakes = excluded.common_mistakes, red_flags = excluded.red_flags, clinical_pearls = excluded.clinical_pearls, introduction = excluded.introduction, etiology = excluded.etiology, transmission = excluded.transmission, pathophysiology = excluded.pathophysiology, epidemiology = excluded.epidemiology, clinical_presentation = excluded.clinical_presentation, physical_exam = excluded.physical_exam, differential_diagnoses = excluded.differential_diagnoses, diagnostics = excluded.diagnostics, diagnostic_approach = excluded.diagnostic_approach, treatment = excluded.treatment, prognosis = excluded.prognosis, complications = excluded.complications, prevention = excluded.prevention, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'infecciosas'), 'miltefosina', 'Miltefosina', 'Miltefosina', array['Milteforan']::text[], 'Leishmanicida', array['dog']::text[], array['Leishmaniose', 'Oral']::text[], 'Análogo de fosfolipídeo que interfere na membrana celular e em vias metabólicas do parasita, reduzindo a viabilidade de Leishmania spp.', array['Tratamento da leishmaniose visceral canina em protocolo clínico supervisionado.']::text[], array['Gestação ou lactação.', 'Hipersensibilidade conhecida ao princípio ativo.']::text[], array['Administrar com alimento para reduzir vômito.', 'Monitorar função renal, hepática e tolerância gastrointestinal.', 'Orientar manejo cuidadoso do medicamento por pessoas gestantes.']::text[], array['Vômito e diarreia.', 'Hiporexia ou apatia transitória.', 'Elevação transitória de enzimas hepáticas.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-miltefosina-lvc","species":"dog","indication":"Leishmaniose visceral canina","doseMin":2,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"SID por 28 dias","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-miltefosina-solucao","label":"Solução oral 20 mg/mL","form":"Solução oral","concentrationValue":20,"concentrationUnit":"mg/mL"}]'::jsonb, '<p>Usar sempre com alimento e integrar o tratamento ao estadiamento clínico e renal do paciente. Na rotina, costuma ser combinada ao alopurinol e ao controle vetorial.</p>', '', '[{"citationText":"Brasileish. Diretrizes Brasileiras para o Manejo da Leishmaniose Visceral Canina (2020).","sourceType":"Consenso","url":"https://www.brasileish.com.br/wp-content/uploads/2020/12/Diretrizes-Brasileish-2020.pdf","notes":"Referência prática para protocolos com miltefosina na LVC."},{"citationText":"Virbac. Milteforan (miltefosina) para leishmaniose canina.","sourceType":"Produto","url":"https://www.virbac.com","notes":"Base comercial e regulatória do produto veterinário."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'infecciosas'), 'alopurinol', 'Alopurinol', 'Alopurinol', array['Zyloric', 'Genéricos']::text[], 'Leishmaniostático / Inibidor da xantina oxidase', array['dog', 'cat']::text[], array['Leishmaniose', 'Oral', 'Urolitíase']::text[], 'Inibe a xantina oxidase e, na leishmaniose, atua como análogo de purina com efeito leishmaniostático.', array['Tratamento adjuvante da leishmaniose visceral canina.', 'Controle de pacientes com predisposição a urólitos de urato em cenários selecionados.']::text[], array['Hipersensibilidade ao fármaco.', 'Uso sem monitorização em pacientes com doença renal avançada.']::text[], array['Monitorar formação de cristais ou urólitos de xantina em uso prolongado.', 'Reavaliar urinálise e imagem em pacientes sintomáticos.']::text[], array['Xantinúria e urolitíase.', 'Distúrbios gastrointestinais.', 'Reações cutâneas de hipersensibilidade.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-alopurinol-lvc","species":"dog","indication":"Leishmaniose visceral canina","doseMin":10,"doseMax":10,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"BID","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-alopurinol-100","label":"Comprimido 100 mg","form":"Comprimido","scoringInfo":"Sulcado"},{"id":"pres-alopurinol-300","label":"Comprimido 300 mg","form":"Comprimido","scoringInfo":"Sulcado"}]'::jsonb, '<p>Em terapia prolongada para leishmaniose, considerar dieta com menor teor de purinas e reavaliação urinária seriada para detectar xantinúria precocemente.</p>', '', '[{"citationText":"Brasileish. Diretrizes Brasileiras para o Manejo da Leishmaniose Visceral Canina (2020).","sourceType":"Consenso","url":"https://www.brasileish.com.br/wp-content/uploads/2020/12/Diretrizes-Brasileish-2020.pdf","notes":"Uso de alopurinol como terapia de suporte e manutenção na LVC."},{"citationText":"LeishVet Group. Practical management of canine leishmaniosis.","sourceType":"Guideline","url":"https://www.leishvet.org","notes":"Contexto internacional para indicação, seguimento e cautelas."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'gastroenterologia'), 'maropitant', 'Maropitant', 'Citrato de maropitant', array['Cerenia']::text[], 'Antiemético', array['dog', 'cat']::text[], array['Náusea', 'Vômito', 'Internação']::text[], 'Antagonista do receptor NK1, reduzindo a ação da substância P em centros relacionados ao vômito.', array['Controle de vômito agudo em cães e gatos.', 'Suporte em pacientes com cinomose, doença renal crônica e outras enfermidades sistêmicas com náusea.']::text[], array['Hipersensibilidade ao princípio ativo.']::text[], array['Ajustar a expectativa em pacientes com obstrução gastrointestinal, onde o controle de vômito não substitui diagnóstico.', 'Usar com critério em hepatopatas.']::text[], array['Dor à aplicação subcutânea.', 'Hipersalivação ou letargia discreta.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-maropitant-dog","species":"dog","indication":"Vômito agudo em cães","doseMin":1,"doseMax":1,"doseUnit":"mg","perWeightUnit":"kg","route":"SC/VO","frequency":"SID","calculatorEnabled":true},{"id":"dose-maropitant-cat","species":"cat","indication":"Vômito agudo em gatos","doseMin":1,"doseMax":1,"doseUnit":"mg","perWeightUnit":"kg","route":"SC","frequency":"SID","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-maropitant-injetável","label":"Solução injetável 10 mg/mL","form":"Solução injetável","concentrationValue":10,"concentrationUnit":"mg/mL"}]'::jsonb, '<p>Útil para estabilização de pacientes com cinomose, DRC ou gastroenteropatia. O controle do vômito melhora conforto, hidratação e adesão ao suporte nutricional.</p>', '', '[{"citationText":"US FDA. Cerenia (maropitant citrate) prescribing information.","sourceType":"Drug label","url":"https://www.fda.gov","notes":"Base regulatória para indicações e vias de administração."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'neurologia'), 'fenobarbital', 'Fenobarbital', 'Fenobarbital', array['Gardenal', 'Genéricos']::text[], 'Anticonvulsivante barbitúrico', array['dog', 'cat']::text[], array['Convulsão', 'Neurológico', 'Manutenção']::text[], 'Potencializa a neurotransmissão gabaérgica e reduz a excitabilidade neuronal, aumentando o limiar convulsivo.', array['Controle de convulsões recorrentes.', 'Manutenção anticonvulsivante em pacientes neurológicos, inclusive com sequelas de cinomose.']::text[], array['Hepatopatia grave sem monitorização.', 'Hipersensibilidade conhecida ao fármaco.']::text[], array['Monitorar função hepática e concentração sérica quando uso prolongado.', 'Ajustar desmame e escalonamento para evitar descompensações.']::text[], array['Sedação, polifagia e poliuria/polidipsia.', 'Elevação de enzimas hepáticas.', 'Ataxia transitória no início do tratamento.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-fenobarbital-dog","species":"dog","indication":"Manutenção anticonvulsivante em cães","doseMin":2.5,"doseMax":3,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"BID","calculatorEnabled":true},{"id":"dose-fenobarbital-cat","species":"cat","indication":"Manutenção anticonvulsivante em gatos","doseMin":1.5,"doseMax":2.5,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"BID","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-fenobarbital-15","label":"Comprimido 15 mg","form":"Comprimido","scoringInfo":"Sulcado"},{"id":"pres-fenobarbital-30","label":"Comprimido 30 mg","form":"Comprimido","scoringInfo":"Sulcado"},{"id":"pres-fenobarbital-100","label":"Comprimido 100 mg","form":"Comprimido","scoringInfo":"Sulcado"}]'::jsonb, '<p>Em pacientes com cinomose neurológica, o objetivo é controle sintomático das crises e melhor qualidade de vida. Ajustes devem considerar resposta clínica e tolerância.</p>', '', '[{"citationText":"MSD Veterinary Manual. Seizure Disorders in Dogs and Cats.","sourceType":"Manual","url":"https://www.msdvetmanual.com","notes":"Referência de uso anticonvulsivante e monitorização clínica."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'infecciosas'), 'amoxicilina-clavulanato', 'Amoxicilina + clavulanato', 'Amoxicilina trihidratada + clavulanato de potássio', array['Synulox', 'Clavulin']::text[], 'Antibiótico beta-lactâmico potencializado', array['dog', 'cat']::text[], array['Suporte', 'Bacteriana secundária', 'VO']::text[], 'A amoxicilina inibe a síntese da parede bacteriana; o clavulanato bloqueia beta-lactamases e amplia a cobertura contra alguns patógenos produtores dessas enzimas.', array['Infecções bacterianas de tecidos moles, vias respiratórias e trato urinário em cenários compatíveis.', 'Cobertura de suporte em paciente com cinomose quando houver suspeita consistente de broncopneumonia ou infecção bacteriana secundária.']::text[], array['Hipersensibilidade a penicilinas ou cefalosporinas.', 'Uso empírico sem indício clínico de infecção bacteriana secundária.']::text[], array['Reavaliar resposta clínica em 48 a 72 horas e ajustar conforme cultura quando disponível.', 'Evitar usar como rotina em toda cinomose sem justificativa infecciosa.']::text[], array['Vômito, diarreia e hiporexia.', 'Hipersensibilidade cutânea ou sistêmica em pacientes suscetíveis.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-amox-clav-dog","species":"dog","indication":"Infecção bacteriana secundária em cães","doseMin":12.5,"doseMax":25,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"BID","calculatorEnabled":true},{"id":"dose-amox-clav-cat","species":"cat","indication":"Infecção bacteriana em gatos","doseMin":12.5,"doseMax":20,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"BID","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-amox-clav-50","label":"Comprimido 50 mg","form":"Comprimido","scoringInfo":"Sulcado"},{"id":"pres-amox-clav-250","label":"Comprimido 250 mg","form":"Comprimido","scoringInfo":"Sulcado"}]'::jsonb, '<p>Na demonstração da cinomose, entra como exemplo de antibiótico de suporte apenas quando o exame clínico sugere complicação bacteriana secundária. Não substitui suporte intensivo, isolamento e monitorização neurológica.</p>', '', '[{"citationText":"NOAH Compendium. Synulox tablets for dogs and cats.","sourceType":"SPC","url":"https://www.noahcompendium.co.uk","notes":"Resumo de características do produto com amoxicilina + clavulanato."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

insert into public.consulta_vet_medications (category_id, slug, title, active_ingredient, trade_names, pharmacologic_class, species, tags, mechanism_of_action, indications, contraindications, cautions, adverse_effects, interactions, routes, doses, presentations, clinical_notes_rich_text, admin_notes_text, "references", is_published)
values ((select id from public.consulta_vet_categories where slug = 'cardiologia'), 'amlodipina', 'Amlodipina', 'Besilato de amlodipina', array['Norvasc', 'Genéricos']::text[], 'Bloqueador de canal de cálcio', array['dog', 'cat']::text[], array['Hipertensão', 'Renal', 'VO']::text[], 'Bloqueia canais de cálcio do músculo liso vascular, promovendo vasodilatação arterial e redução da pressão sistólica.', array['Hipertensão arterial sistêmica, especialmente em pacientes com doença renal crônica.']::text[], array['Hipotensão não corrigida.', 'Uso sem monitorização pressórica.']::text[], array['Reavaliar pressão arterial após início ou ajuste de dose.', 'Cautela em pacientes muito desidratados ou com baixo débito.']::text[], array['Hipotensão.', 'Letargia ou anorexia em casos sensíveis.']::text[], array[]::text[], array[]::text[], '[{"id":"dose-amlodipina-dog","species":"dog","indication":"Hipertensão sistêmica em cães","doseMin":0.1,"doseMax":0.2,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"SID","calculatorEnabled":true},{"id":"dose-amlodipina-cat","species":"cat","indication":"Hipertensão sistêmica em gatos","doseMin":0.125,"doseMax":0.25,"doseUnit":"mg","perWeightUnit":"kg","route":"VO","frequency":"SID","calculatorEnabled":true}]'::jsonb, '[{"id":"pres-amlodipina-5","label":"Comprimido 5 mg","form":"Comprimido","scoringInfo":"Sulcado"},{"id":"pres-amlodipina-10","label":"Comprimido 10 mg","form":"Comprimido","scoringInfo":"Sulcado"}]'::jsonb, '<p>É uma das opções mais utilizadas para controle pressórico em DRC, especialmente em gatos. O acompanhamento seriado da PAS é obrigatório após introdução e titulação.</p>', '', '[{"citationText":"International Renal Interest Society (IRIS). IRIS Staging of CKD modified 2023.","sourceType":"Guideline","url":"http://www.iris-kidney.com/pdf/IRIS_Staging_of_CKD_modified_2023.pdf","notes":"Contexto de controle pressórico em pacientes com DRC."},{"citationText":"US FDA. Norvasc (amlodipine besylate) prescribing information.","sourceType":"Drug label","url":"https://www.fda.gov","notes":"Base farmacológica do ativo usado na prática clínica."}]'::jsonb, true)
on conflict (slug) do update set category_id = excluded.category_id, title = excluded.title, active_ingredient = excluded.active_ingredient, trade_names = excluded.trade_names, pharmacologic_class = excluded.pharmacologic_class, species = excluded.species, tags = excluded.tags, mechanism_of_action = excluded.mechanism_of_action, indications = excluded.indications, contraindications = excluded.contraindications, cautions = excluded.cautions, adverse_effects = excluded.adverse_effects, interactions = excluded.interactions, routes = excluded.routes, doses = excluded.doses, presentations = excluded.presentations, clinical_notes_rich_text = excluded.clinical_notes_rich_text, admin_notes_text = excluded.admin_notes_text, "references" = excluded."references", is_published = excluded.is_published;

delete from public.consulta_vet_disease_medications where disease_id in (select id from public.consulta_vet_diseases where slug in ('cinomose-canina', 'leishmaniose-visceral-canina', 'doenca-renal-cronica'));

insert into public.consulta_vet_disease_medications (disease_id, medication_id)
select d.id, m.id
from public.consulta_vet_diseases d
join public.consulta_vet_medications m on m.slug in ('maropitant', 'fenobarbital', 'amoxicilina-clavulanato')
where d.slug = 'cinomose-canina'
on conflict do nothing;

insert into public.consulta_vet_disease_medications (disease_id, medication_id)
select d.id, m.id
from public.consulta_vet_diseases d
join public.consulta_vet_medications m on m.slug in ('miltefosina', 'alopurinol')
where d.slug = 'leishmaniose-visceral-canina'
on conflict do nothing;

insert into public.consulta_vet_disease_medications (disease_id, medication_id)
select d.id, m.id
from public.consulta_vet_diseases d
join public.consulta_vet_medications m on m.slug in ('amlodipina', 'maropitant')
where d.slug = 'doenca-renal-cronica'
on conflict do nothing;

delete from public.consulta_vet_disease_consensos where disease_id in (select id from public.consulta_vet_diseases where slug in ('cinomose-canina', 'leishmaniose-visceral-canina', 'doenca-renal-cronica'));

insert into public.consulta_vet_disease_consensos (disease_id, consensus_document_id)
select d.id, c.id
from public.consulta_vet_diseases d
join public.consensus_documents c on c.slug in ('leishmaniose-brasileiro-2020')
where d.slug = 'leishmaniose-visceral-canina'
on conflict do nothing;

insert into public.consulta_vet_disease_consensos (disease_id, consensus_document_id)
select d.id, c.id
from public.consulta_vet_diseases d
join public.consensus_documents c on c.slug in ('iris-drc-2023')
where d.slug = 'doenca-renal-cronica'
on conflict do nothing;

insert into public.consensus_document_details (consensus_document_id, "references")
select id, '[{"citationText":"Brasileish. Diretrizes Brasileiras para o Manejo da Leishmaniose Visceral Canina (2020).","sourceType":"Consenso","url":"https://www.brasileish.com.br/wp-content/uploads/2020/12/Diretrizes-Brasileish-2020.pdf","notes":"Documento-base para diagnóstico, estadiamento e tratamento da LVC no Brasil."}]'::jsonb
from public.consensus_documents
where slug = 'leishmaniose-brasileiro-2020'
on conflict (consensus_document_id) do update
set "references" = excluded."references";

insert into public.consensus_document_details (consensus_document_id, "references")
select id, '[{"citationText":"International Renal Interest Society (IRIS). IRIS Staging of CKD modified 2023.","sourceType":"Guideline","url":"http://www.iris-kidney.com/pdf/IRIS_Staging_of_CKD_modified_2023.pdf","notes":"Estadiamento, subestadiamento e monitorização de DRC em cães e gatos."}]'::jsonb
from public.consensus_documents
where slug = 'iris-drc-2023'
on conflict (consensus_document_id) do update
set "references" = excluded."references";

